// Get configuration from Workflow Configuration node
const config = $('Workflow Configuration').first().json;
const chunkSize = config.chunkSize || 1000;
const chunkOverlap = config.chunkOverlap || 200;
const sourceRevision = config.sourceRevision || 'v1';

// Get documents from previous node
const documents = $input.all();

// Function to calculate SHA-256 hash
const crypto = require('crypto');
function calculateHash(text) {
  return crypto.createHash('sha256').update(text).digest('hex');
}

// Function to chunk text with deterministic splitting
function chunkText(text, size, overlap) {
  const chunks = [];
  let start = 0;

  while (start < text.length) {
    const end = Math.min(start + size, text.length);
    const chunk = text.substring(start, end);
    chunks.push(chunk);

    if (end >= text.length) break;
    start += size - overlap;
  }

  return chunks;
}

// Process all documents and create chunks
const results = [];
const timestamp = new Date().toISOString();

for (const doc of documents) {
  const content = doc.json.content || doc.json.text || JSON.stringify(doc.json);
  const chunks = chunkText(content, chunkSize, chunkOverlap);

  chunks.forEach((chunk, index) => {
    const hash = calculateHash(chunk);
    const chunkId = `${doc.json.id || 'doc'}_chunk_${index}`;

    results.push({
      chunkId: chunkId,
      content: chunk,
      hash: hash,
      chunkSize: chunkSize,
      chunkOverlap: chunkOverlap,
      sourceRevision: sourceRevision,
      timestamp: timestamp
    });
  });
}

return results.map(item => ({ json: item }));

// Extract embedding metadata including model name, version, timestamp, and source revision

const items = $input.all();

// Get configuration from Workflow Configuration node
const config = $('Workflow Configuration').first().json;

// Extract metadata
const embeddingModel = config.embeddingModel || 'text-embedding-ada-002';
const modelVersion = config.modelVersion || 'v2';
const embeddingTimestamp = new Date().toISOString();
const sourceRevision = config.sourceRevision || $('Fetch Documents from Source').first().json.revision || 'latest';
const chunkCount = items.length;

// Return metadata object
return [{
  json: {
    embeddingModel: embeddingModel,
    modelVersion: modelVersion,
    embeddingTimestamp: embeddingTimestamp,
    sourceRevision: sourceRevision,
    chunkCount: chunkCount
  }
}];

// Calculate quality metrics comparing new vs old answers
const items = $input.all();

// Separate new and old answers
const newAnswers = items.filter(item => item.json.answerType === 'new');
const oldAnswers = items.filter(item => item.json.answerType === 'old');

// Initialize metrics
let totalRecallAtK = 0;
let totalSimilarityScore = 0;
let totalAnswerLengthVariance = 0;
const k = 5; // Top-k passages to consider

// Process each question
for (let i = 0; i < newAnswers.length; i++) {
  const newAnswer = newAnswers[i].json;
  const oldAnswer = oldAnswers[i].json;

  // Calculate Recall@K - check if expected passages were retrieved
  const expectedPassages = newAnswer.expectedPassages || [];
  const retrievedPassages = newAnswer.retrievedPassages || [];
  const topKRetrieved = retrievedPassages.slice(0, k);

  let retrievedCount = 0;
  for (const expected of expectedPassages) {
    if (topKRetrieved.some(retrieved => retrieved.includes(expected))) {
      retrievedCount++;
    }
  }

  const recallAtK = expectedPassages.length > 0 ? retrievedCount / expectedPassages.length : 0;
  totalRecallAtK += recallAtK;

  // Calculate similarity score between answer and expected keywords
  const expectedKeywords = newAnswer.expectedKeywords || [];
  const answerText = (newAnswer.answer || '').toLowerCase();

  let keywordMatches = 0;
  for (const keyword of expectedKeywords) {
    if (answerText.includes(keyword.toLowerCase())) {
      keywordMatches++;
    }
  }

  const similarityScore = expectedKeywords.length > 0 ? keywordMatches / expectedKeywords.length : 0;
  totalSimilarityScore += similarityScore;

  // Calculate answer length variance
  const newLength = (newAnswer.answer || '').length;
  const oldLength = (oldAnswer.answer || '').length;
  const avgLength = (newLength + oldLength) / 2;
  const lengthVariance = avgLength > 0 ? Math.abs(newLength - oldLength) / avgLength : 0;
  totalAnswerLengthVariance += lengthVariance;
}

const numQuestions = newAnswers.length || 1;

// Calculate average metrics
const avgRecallAtK = totalRecallAtK / numQuestions;
const avgSimilarityScore = totalSimilarityScore / numQuestions;
const avgAnswerLengthVariance = totalAnswerLengthVariance / numQuestions;

// Calculate weighted quality score
// Higher recall and similarity = better, lower variance = better
const qualityScore = (
  (avgRecallAtK * 0.4) + 
  (avgSimilarityScore * 0.4) + 
  ((1 - avgAnswerLengthVariance) * 0.2)
);

return [
  {
    json: {
      recallAtK: avgRecallAtK,
      similarityScore: avgSimilarityScore,
      answerLengthVariance: avgAnswerLengthVariance,
      qualityScore: qualityScore,
      numQuestionsEvaluated: numQuestions,
      timestamp: new Date().toISOString()
    }
  }
];

// Calculate Embedding Drift between old and new embeddings
// This compares embedding vectors to detect semantic drift

const items = $input.all();

// Helper function to calculate cosine distance between two vectors
function cosineDistance(vecA, vecB) {
  if (!vecA || !vecB || vecA.length !== vecB.length) {
    return null;
  }

  let dotProduct = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < vecA.length; i++) {
    dotProduct += vecA[i] * vecB[i];
    normA += vecA[i] * vecA[i];
    normB += vecB[i] * vecB[i];
  }

  normA = Math.sqrt(normA);
  normB = Math.sqrt(normB);

  if (normA === 0 || normB === 0) {
    return null;
  }

  const cosineSimilarity = dotProduct / (normA * normB);
  return 1 - cosineSimilarity; // Convert similarity to distance
}

// Fetch embedding vectors from both versions
const oldEmbeddings = items.filter(item => item.json.version === 'old').map(item => item.json.embedding);
const newEmbeddings = items.filter(item => item.json.version === 'new').map(item => item.json.embedding);

// Calculate drift scores
const driftScores = [];

for (let i = 0; i < Math.min(oldEmbeddings.length, newEmbeddings.length); i++) {
  const distance = cosineDistance(oldEmbeddings[i], newEmbeddings[i]);
  if (distance !== null) {
    driftScores.push(distance);
  }
}

// Calculate statistics
const avgDrift = driftScores.length > 0 
  ? driftScores.reduce((sum, score) => sum + score, 0) / driftScores.length 
  : 0;

const maxDrift = driftScores.length > 0 
  ? Math.max(...driftScores) 
  : 0;

// Get drift threshold from workflow configuration
const config = $('Workflow Configuration').first().json;
const driftThreshold = config.driftThreshold || 0.15; // Default threshold

// Return drift analysis
return [{
  json: {
    driftScore: avgDrift,
    maxDrift: maxDrift,
    avgDrift: avgDrift,
    driftThreshold: driftThreshold,
    driftDetected: avgDrift > driftThreshold,
    numComparisons: driftScores.length,
    timestamp: new Date().toISOString()
  }
}];
